```cpp
class Solution {
public:
    // Candidate 表示一个候选 AP 放置方案
    struct Candidate {
        // fullMask：该 AP 的 3×3 覆盖区域占用了哪些实际格子
        std::bitset<2500> fullMask;

        // emptyMask：该 AP 覆盖了哪些空地
        std::bitset<2500> emptyMask;

        // coveredEmptyList：该 AP 覆盖到的空地下标列表
        std::vector<int> coveredEmptyList;
    };

    int networkPlanning(std::vector<std::vector<char> >& roomArrangement) {
        // 获取行数
        int m = (int)roomArrangement.size();
        if (m == 0) {
            return 0;
        }

        // 获取列数
        int n = (int)roomArrangement[0].size();

        // 给每个空地分配编号，不是空地则为 -1
        std::vector<std::vector<int>> emptyId(m, std::vector<int>(n, -1));

        // 记录所有空地坐标，便于统计空地总数
        std::vector<std::pair<int, int>> emptyCells;

        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (roomArrangement[i][j] == '.') {
                    emptyId[i][j] = (int)emptyCells.size();
                    emptyCells.push_back({i, j});
                }
            }
        }

        // 空地总数
        int totalEmpty = (int)emptyCells.size();

        // 没有空地，不需要放 AP
        if (totalEmpty == 0) {
            return 0;
        }

        // 保存所有候选 AP
        std::vector<Candidate> candidates;

        // coversOfEmpty[eid]：所有能覆盖第 eid 个空地的候选 AP 编号
        std::vector<std::vector<int>> coversOfEmpty(totalEmpty);

        // 枚举每个可放 AP 的位置
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                // 只有空地可以放置 AP
                if (roomArrangement[i][j] != '.') {
                    continue;
                }

                Candidate cur;

                // 枚举这个 AP 的 3×3 覆盖区域
                for (int x = std::max(0, i - 1); x <= std::min(m - 1, i + 1); x++) {
                    for (int y = std::max(0, j - 1); y <= std::min(n - 1, j + 1); y++) {
                        // 标记它占用的实际格子
                        int fullIndex = x * n + y;
                        cur.fullMask.set(fullIndex);

                        // 如果该格子是空地，则它也会被覆盖
                        if (roomArrangement[x][y] == '.') {
                            int eid = emptyId[x][y];
                            cur.emptyMask.set(eid);
                            cur.coveredEmptyList.push_back(eid);
                        }
                    }
                }

                // 当前候选编号
                int cid = (int)candidates.size();
                candidates.push_back(cur);

                // 建立反向索引：这些空地可以被当前候选覆盖
                for (int eid : cur.coveredEmptyList) {
                    coversOfEmpty[eid].push_back(cid);
                }
            }
        }

        // 如果存在某块空地没有任何候选能覆盖，直接无解
        for (int eid = 0; eid < totalEmpty; eid++) {
            if (coversOfEmpty[eid].empty()) {
                return -1;
            }
        }

        // allCovered 表示“所有空地都被覆盖”的目标状态
        std::bitset<2500> allCovered;
        for (int i = 0; i < totalEmpty; i++) {
            allCovered.set(i);
        }

        // 当前最优答案
        int best = INT_MAX;

        // 深度优先搜索
        std::function<void(std::bitset<2500>, std::bitset<2500>, int)> dfs =
            [&](std::bitset<2500> coveredEmptyMask,
                std::bitset<2500> occupiedFullMask,
                int usedCount) {
                // 剪枝：已使用 AP 数不优于当前最优解
                if (usedCount >= best) {
                    return;
                }

                // 若全部空地都已覆盖，则更新最优答案
                if (coveredEmptyMask == allCovered) {
                    best = usedCount;
                    return;
                }

                // targetList 保存“当前被选中的目标空地”对应的所有合法候选 AP
                std::vector<int> targetList;
                int minChoices = INT_MAX;

                // 找一个尚未覆盖的空地，并优先选合法候选最少的那个
                for (int eid = 0; eid < totalEmpty; eid++) {
                    if (coveredEmptyMask.test(eid)) {
                        continue;
                    }

                    std::vector<int> valid;

                    // 枚举所有能覆盖这个空地的候选 AP
                    for (int cid : coversOfEmpty[eid]) {
                        // 如果当前候选的 3×3 区域和已选 AP 的覆盖区域有交集
                        // 就说明发生重叠，不能选
                        if ((candidates[cid].fullMask & occupiedFullMask).any()) {
                            continue;
                        }
                        valid.push_back(cid);
                    }

                    // 当前这个尚未覆盖的空地已经没有合法候选
                    // 当前搜索分支失败
                    if (valid.empty()) {
                        return;
                    }

                    // 采用“候选最少优先”的策略，减少分支
                    if ((int)valid.size() < minChoices) {
                        minChoices = (int)valid.size();
                        targetList = valid;
                        if (minChoices == 1) {
                            break;
                        }
                    }
                }

                // 枚举当前目标空地的所有合法候选 AP
                for (int cid : targetList) {
                    dfs(
                        // 新的已覆盖空地状态
                        coveredEmptyMask | candidates[cid].emptyMask,

                        // 新的已占用实际格子状态
                        occupiedFullMask | candidates[cid].fullMask,

                        // AP 数量 +1
                        usedCount + 1
                    );
                }
            };

        // 从空状态开始搜索
        dfs(std::bitset<2500>(), std::bitset<2500>(), 0);

        // 如果没有找到可行解，则返回 -1
        return best == INT_MAX ? -1 : best;
    }
};
