#include <stdlib.h>
#include <string.h>
#include <stdbool.h>
#include <limits.h>

#define MAX_CELLS 2500
#define BITSET_WORDS ((MAX_CELLS + 63) / 64)

typedef unsigned long long uint64;

static bool bitsetEq(const uint64* a, const uint64* b, int words) {
    for (int i = 0; i < words; i++)
        if (a[i] != b[i]) return false;
    return true;
}

static void bitsetOr(uint64* a, const uint64* b, int words) {
    for (int i = 0; i < words; i++) a[i] |= b[i];
}

static bool bitsetIntersects(const uint64* a, const uint64* b, int words) {
    for (int i = 0; i < words; i++)
        if (a[i] & b[i]) return true;
    return false;
}

static int bestAns;
static int totalEmpty;
static int candCount;
static uint64* candFull;
static uint64* candEmpty;
static int* candEmptyCnt;
static int** candEmptyList;
static int** coversOfEmpty;
static int* coversOfEmptyLen;
static uint64* allCovered;
static int fullWords, emptyWords;

static void dfsHelp(uint64* coveredEmpty, uint64* occupiedFull, int used, int rowCount, int colCount) {
    if (used >= bestAns) return;
    if (bitsetEq(coveredEmpty, allCovered, emptyWords)) {
        bestAns = used;
        return;
    }

    int targetEid = -1;
    int minChoices = INT_MAX;
    int savedCnt = 0;
    int savedCids[MAX_CELLS];

    for (int eid = 0; eid < totalEmpty; eid++) {
        if (coveredEmpty[eid >> 6] & (1ULL << (eid & 63))) continue;

        int cnt = 0;
        int validBuf[MAX_CELLS];
        for (int k = 0; k < coversOfEmptyLen[eid]; k++) {
            int cid = coversOfEmpty[eid][k];
            if (!bitsetIntersects(candFull + cid * fullWords, occupiedFull, fullWords)) {
                validBuf[cnt++] = cid;
            }
        }

        if (cnt == 0) return;
        if (cnt < minChoices) {
            minChoices = cnt;
            targetEid = eid;
            memcpy(savedCids, validBuf, cnt * sizeof(int));
            savedCnt = cnt;
            if (cnt == 1) break;
        }
    }

    if (targetEid == -1) return;

    int maxWords = (fullWords > emptyWords) ? fullWords : emptyWords;
    uint64 nextCovered[maxWords];
    uint64 nextOccupied[maxWords];

    for (int k = 0; k < savedCnt; k++) {
        int cid = savedCids[k];
        memcpy(nextCovered, coveredEmpty, emptyWords * sizeof(uint64));
        memcpy(nextOccupied, occupiedFull, fullWords * sizeof(uint64));
        bitsetOr(nextCovered, candEmpty + cid * emptyWords, emptyWords);
        bitsetOr(nextOccupied, candFull + cid * fullWords, fullWords);
        dfsHelp(nextCovered, nextOccupied, used + 1, rowCount, colCount);
        if (bestAns == 1) return;
    }
}

int networkPlanning(char** roomArrangement, int rows) {
    if (rows == 0) return 0;
    int cols = 0;
    while (roomArrangement[0][cols]) cols++;
    if (cols == 0) return 0;

    fullWords = (rows * cols + 63) / 64;
    int emptyId[rows * cols];
    memset(emptyId, -1, sizeof(emptyId));

    int* emptyRow = (int*)malloc(MAX_CELLS * sizeof(int));
    int* emptyCol = (int*)malloc(MAX_CELLS * sizeof(int));
    totalEmpty = 0;

    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            if (roomArrangement[i][j] == '.') {
                emptyId[i * cols + j] = totalEmpty;
                emptyRow[totalEmpty] = i;
                emptyCol[totalEmpty] = j;
                totalEmpty++;
            }
        }
    }

    if (totalEmpty == 0) {
        free(emptyRow); free(emptyCol);
        return 0;
    }

    emptyWords = (totalEmpty + 63) / 64;
    int maxCands = totalEmpty;
    candFull = (uint64*)calloc(maxCands * fullWords, sizeof(uint64));
    candEmpty = (uint64*)calloc(maxCands * emptyWords, sizeof(uint64));
    candEmptyCnt = (int*)calloc(maxCands, sizeof(int));
    candEmptyList = (int**)malloc(maxCands * sizeof(int*));
    candCount = 0;

    coversOfEmpty = (int**)malloc(totalEmpty * sizeof(int*));
    coversOfEmptyLen = (int*)calloc(totalEmpty, sizeof(int));
    for (int i = 0; i < totalEmpty; i++) {
        coversOfEmpty[i] = (int*)malloc(MAX_CELLS * sizeof(int));
    }

    for (int r = 0; r < rows; r++) {
        for (int c = 0; c < cols; c++) {
            if (roomArrangement[r][c] != '.') continue;
            int cid = candCount;
            uint64* cf = candFull + cid * fullWords;
            uint64* ce = candEmpty + cid * emptyWords;
            int eList[9];
            int ecnt = 0;

            for (int dr = -1; dr <= 1; dr++) {
                int nr = r + dr;
                if (nr < 0 || nr >= rows) continue;
                for (int dc = -1; dc <= 1; dc++) {
                    int nc = c + dc;
                    if (nc < 0 || nc >= cols) continue;
                    int idx = nr * cols + nc;
                    cf[idx >> 6] |= 1ULL << (idx & 63);
                    if (roomArrangement[nr][nc] == '.') {
                        int eid = emptyId[idx];
                        ce[eid >> 6] |= 1ULL << (eid & 63);
                        eList[ecnt++] = eid;
                    }
                }
            }

            candEmptyList[cid] = (int*)malloc(ecnt * sizeof(int));
            memcpy(candEmptyList[cid], eList, ecnt * sizeof(int));
            candEmptyCnt[cid] = ecnt;

            for (int k = 0; k < ecnt; k++) {
                int eid = eList[k];
                int idx = coversOfEmptyLen[eid]++;
                coversOfEmpty[eid][idx] = cid;
            }
            candCount++;
        }
    }

    for (int eid = 0; eid < totalEmpty; eid++) {
        if (coversOfEmptyLen[eid] == 0) return -1;
    }

    allCovered = (uint64*)calloc(emptyWords, sizeof(uint64));
    for (int i = 0; i < totalEmpty; i++)
        allCovered[i >> 6] |= 1ULL << (i & 63);

    bestAns = INT_MAX;
    uint64* initCovered = (uint64*)calloc(emptyWords, sizeof(uint64));
    uint64* initOccupied = (uint64*)calloc(fullWords, sizeof(uint64));
    dfsHelp(initCovered, initOccupied, 0, rows, cols);

    return (bestAns == INT_MAX) ? -1 : bestAns;
}
